-- 010_stylex_latex_colours.sql
-- Generated by _inbox/generate_stylex_migration.py from the scraped
-- Stylex Balloons colour list at https://stylexballoons.com.au/pages/colous
-- (50 colours, all 5-inch latex). Don't hand-edit this file — re-run
-- the generator if the colour list changes upstream.
--
-- What this migration does:
--   1. Adds a `photo_url` column to inventory_items
--   2. Archives the previous 20 ad-hoc latex colour SKUs (kept the mixed
--      `balloon-latex-5in-pack` for recipe compatibility)
--   3. Inserts 50 fresh SKUs matching Stylex's catalogue, each with
--      photo_url + Stylex supplier source pointing at the specific
--      product collection page
--   4. Adds Hayden Agencies + Online Party Supplies as backup sources
--      (no URLs — Jade fills in over time)

-- 1. Add photo_url column. Idempotent-safe via column-not-exists check
--    pattern: SQLite doesn't support IF NOT EXISTS on ALTER TABLE so we
--    let it raise on a re-run; the migration runner only applies each
--    version once anyway.
ALTER TABLE inventory_items ADD COLUMN photo_url TEXT;

-- 2. Archive the previous 20 hand-rolled colour rows (preserves history;
--    Jade can restore via the Show-archived toggle if needed). The mixed
--    pack stays because recipes still reference its sku.
UPDATE inventory_items
   SET archived = 1, updated_at = datetime('now')
 WHERE category = 'Balloons - Latex'
   AND sku != 'balloon-latex-5in-pack'
   AND sku != 'balloon-latex-5in-stylex-pack';

-- 3. Insert all 50 Stylex colours with photo + product page URLs.
