-- 4. Stylex supplier source for each new SKU — preferred, with the
--    specific product page URL filled in. Idempotent via NOT EXISTS.
INSERT INTO inventory_supplier_sources (inventory_item_id, supplier_name, url, is_preferred, notes)
  SELECT id, 'Stylex Balloons', 'https://stylexballoons.com.au/collections/avocado-green', 1, 'Stylex catalogue page for Avocado Green.'
  FROM inventory_items WHERE sku = 'balloon-latex-5in-stylex-avocado-green'
  AND NOT EXISTS (SELECT 1 FROM inventory_supplier_sources s WHERE s.inventory_item_id = inventory_items.id AND s.supplier_name = 'Stylex Balloons');
